// ═══════════════════════════════════════════
// EŞİK DEĞERLERİ - BURADAN KOLAYCA DEĞİŞTİR
// ═══════════════════════════════════════════
const THRESHOLDS = {
  USD: { name: 'Dolar', emoji: '💵', upper: 38.00, lower: 36.00 },
  EUR: { name: 'Euro', emoji: '💶', upper: 41.00, lower: 39.00 },
  XAU: { name: 'Altın (ons)', emoji: '🪙', upper: 100000, lower: 85000 }
};
// ═══════════════════════════════════════════

const dovizData = $node['Doviz Kurlari'].json;
const altinData = $node['Altin Kuru'].json;

const rates = {};
if (dovizData && dovizData.rates) {
  rates.USD = dovizData.rates.USD ? parseFloat((1 / dovizData.rates.USD).toFixed(4)) : null;
  rates.EUR = dovizData.rates.EUR ? parseFloat((1 / dovizData.rates.EUR).toFixed(4)) : null;
}
if (altinData && altinData.rates) {
  rates.XAU = altinData.rates.TRY ? parseFloat(altinData.rates.TRY.toFixed(2)) : null;
}

const today = new Date().toLocaleDateString('tr-TR', { timeZone: 'Europe/Istanbul' });
const now = new Date().toLocaleTimeString('tr-TR', { timeZone: 'Europe/Istanbul', hour: '2-digit', minute: '2-digit' });

const alerts = [];
const alertKeys = [];

for (const [currency, config] of Object.entries(THRESHOLDS)) {
  const rate = rates[currency];
  if (rate === null || rate === undefined) continue;
  if (rate > config.upper) {
    alerts.push({ key: `${currency}_upper`, text: `${config.emoji} ${config.name}: ${rate.toLocaleString('tr-TR')} TL\n⬆️ Eşik değer ${config.upper.toLocaleString('tr-TR')} TL üzerine çıktı!` });
    alertKeys.push(`${currency}_upper`);
  }
  if (rate < config.lower) {
    alerts.push({ key: `${currency}_lower`, text: `${config.emoji} ${config.name}: ${rate.toLocaleString('tr-TR')} TL\n⬇️ Eşik değer ${config.lower.toLocaleString('tr-TR')} TL altına düştü!` });
    alertKeys.push(`${currency}_lower`);
  }
}

let message = '';
if (alerts.length > 0) {
  message = `🚨 DÖVİZ KURU UYARI 🚨\n📅 ${today} - ⏰ ${now}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  message += alerts.map(a => a.text).join('\n\n');
  message += `\n\n━━━━━━━━━━━━━━━━━━━━━\n📊 Güncel Kurlar:\n💵 Dolar: ${rates.USD ? rates.USD.toLocaleString('tr-TR') : 'N/A'} TL\n💶 Euro: ${rates.EUR ? rates.EUR.toLocaleString('tr-TR') : 'N/A'} TL\n🪙 Altın: ${rates.XAU ? rates.XAU.toLocaleString('tr-TR') : 'N/A'} TL`;
}

return [{ json: { message, hasAlerts: alerts.length > 0, alertKeys, alertDate: today, rates, alertCount: alerts.length } }];

const alertData = $node['Esik Kontrolu'].json;
const sheetData = items.map(i => i.json);

if (!alertData.hasAlerts || !alertData.message) return [];

const today = alertData.alertDate;
const sentTodayKeys = new Set();
for (const row of sheetData) {
  if (row.alert_date === today) sentTodayKeys.add(row.alert_key);
}

const newAlertKeys = alertData.alertKeys.filter(key => !sentTodayKeys.has(key));
if (newAlertKeys.length === 0) return [];

return [{ json: { message: alertData.message, alertKeys: newAlertKeys, alertDate: today, rates: alertData.rates, shouldSend: true } }];

const data = $json;
const rows = [];
for (const key of data.alertKeys) {
  const currency = key.split('_')[0];
  rows.push({ json: { alert_key: key, alert_date: data.alertDate, rate: data.rates[currency] || '', timestamp: new Date().toLocaleString('tr-TR', { timeZone: 'Europe/Istanbul' }) } });
}
return rows;
